import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (pname, fw['framework'], pkg['id'])
                result[key] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
all_keys = sorted(set(b.keys()) | set(a.keys()))
for k in all_keys:
    proj, fw, pkg = k
    if k in b and k in a:
        if b[k][1] != a[k][1]:
            changes.append((proj, fw, pkg, b[k][1], a[k][1], 'Aligned to highest version'))
        else:
            unchanged.append((proj, fw, pkg, a[k][1]))
    elif k in a and k not in b:
        changes.append((proj, fw, pkg, '-', a[k][1], 'Added'))
    elif k in b and k not in a:
        changes.append((proj, fw, pkg, b[k][1], '-', 'Removed'))

print('=== CHANGES ===')
if changes:
    for c in changes: print(f'{c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')
else:
    print('None')

print()
print('=== UNCHANGED ===')
for u in unchanged: print(f'{u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

